substep.action:
Read {{plan_path_for_current_plan}}. Locate the section
"## Slice {{current_slice.plan_n}}.{{current_slice.slice_id}}: ...".
Extract:
- {{slice_description}}
- {{slice_steps}} (the 1-5 TDD steps)
- {{slice_verification_commands}}
- {{slice_commit_message_format}}

invoke-agent.prompt:
Execute one slice from the implementation plan.

- plan_path: {{plan_path}}
- slice_id: {{current_slice.plan_n}}.{{current_slice.slice_id}}
- worktree_path: {{worktree_path}}
- branch: {{worktree_branch}}
- slice_description: {{slice_description}}
- slice_steps:
{{slice_steps}}
- verification_commands:
{{slice_verification_commands}}
- commit_message_format:
{{slice_commit_message_format}}
